{"content":"650: PlannerInfo *
651: subquery_planner(PlannerGlobal *glob, Query *parse, PlannerInfo *parent_root,
652: 				 bool hasRecursion, double tuple_fraction,
653: 				 SetOperationStmt *setops)
654: {
655: 	PlannerInfo *root;
656: 	List	   *newWithCheckOptions;
657: 	List	   *newHaving;
658: 	bool		hasOuterJoins;
659: 	bool		hasResultRTEs;
660: 	RelOptInfo *final_rel;
661: 	ListCell   *l;
662: 
663: 	/* Create a PlannerInfo data structure for this subquery */
664: 	root = makeNode(PlannerInfo);
665: 	root->parse = parse;
666: 	root->glob = glob;
667: 	root->query_level = parent_root ? parent_root->query_level + 1 : 1;
668: 	root->parent_root = parent_root;
669: 	root->plan_params = NIL;
670: 	root->outer_params = NULL;
671: 	root->planner_cxt = CurrentMemoryContext;
672: 	root->init_plans = NIL;
673: 	root->cte_plan_ids = NIL;
674: 	root->multiexpr_params = NIL;
675: 	root->join_domains = NIL;
676: 	root->eq_classes = NIL;
677: 	root->ec_merging_done = false;
678: 	root->last_rinfo_serial = 0;
679: 	root->all_result_relids =
680: 		parse->resultRelation ? bms_make_singleton(parse->resultRelation) : NULL;
681: 	root->leaf_result_relids = NULL;	/* we'll find out leaf-ness later */
682: 	root->append_rel_list = NIL;
683: 	root->row_identity_vars = NIL;
684: 	root->rowMarks = NIL;
685: 	memset(root->upper_rels, 0, sizeof(root->upper_rels));
686: 	memset(root->upper_targets, 0, sizeof(root->upper_targets));
687: 	root->processed_groupClause = NIL;
688: 	root->processed_distinctClause = NIL;
689: 	root->processed_tlist = NIL;
690: 	root->update_colnos = NIL;
691: 	root->grouping_map = NULL;
692: 	root->minmax_aggs = NIL;
693: 	root->qual_security_level = 0;
694: 	root->hasPseudoConstantQuals = false;
695: 	root->hasAlternativeSubPlans = false;
696: 	root->placeholdersFrozen = false;
697: 	root->hasRecursion = hasRecursion;
698: 	if (hasRecursion)
699: 		root->wt_param_id = assign_special_exec_param(root);
700: 	else
701: 		root->wt_param_id = -1;
702: 	root->non_recursive_path = NULL;
703: 	root->partColsUpdated = false;
704: 
705: 	/*
706: 	 * Create the top-level join domain.  This won't have valid contents until
707: 	 * deconstruct_jointree fills it in, but the node needs to exist before
708: 	 * that so we can build EquivalenceClasses referencing it.
709: 	 */
710: 	root->join_domains = list_make1(makeNode(JoinDomain));
711: 
712: 	/*
713: 	 * If there is a WITH list, process each WITH query and either convert it
714: 	 * to RTE_SUBQUERY RTE(s) or build an initplan SubPlan structure for it.
715: 	 */
716: 	if (parse->cteList)
717: 		SS_process_ctes(root);
718: 
719: 	/*
720: 	 * If it's a MERGE command, transform the joinlist as appropriate.
721: 	 */
722: 	transform_MERGE_to_join(parse);
723: 
724: 	/*
725: 	 * If the FROM clause is empty, replace it with a dummy RTE_RESULT RTE, so
726: 	 * that we don't need so many special cases to deal with that situation.
727: 	 */
728: 	replace_empty_jointree(parse);
729: 
730: 	/*
731: 	 * Look for ANY and EXISTS SubLinks in WHERE and JOIN/ON clauses, and try
732: 	 * to transform them into joins.  Note that this step does not descend
733: 	 * into subqueries; if we pull up any subqueries below, their SubLinks are
734: 	 * processed just before pulling them up.
735: 	 */
736: 	if (parse->hasSubLinks)
737: 		pull_up_sublinks(root);
738: 
739: 	/*
740: 	 * Scan the rangetable for function RTEs, do const-simplification on them,
741: 	 * and then inline them if possible (producing subqueries that might get
742: 	 * pulled up next).  Recursion issues here are handled in the same way as
743: 	 * for SubLinks.
744: 	 */
745: 	preprocess_function_rtes(root);
746: 
747: 	/*
748: 	 * Scan the rangetable for relations with virtual generated columns, and
749: 	 * replace all Var nodes in the query that reference these columns with
750: 	 * the generation expressions.  Recursion issues here are handled in the
751: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/postgres--5a461dc4@eb8f07549ee15f0db57589c5f333de3f874fe855/-/blob/src/backend/optimizer/plan/planner.c%3FL650-750"}

{"content":"750: 	 * the generation expressions.  Recursion issues here are handled in the
751: 	 * same way as for SubLinks.
752: 	 */
753: 	parse = root->parse = expand_virtual_generated_columns(root);
754: 
755: 	/*
756: 	 * Check to see if any subqueries in the jointree can be merged into this
757: 	 * query.
758: 	 */
759: 	pull_up_subqueries(root);
760: 
761: 	/*
762: 	 * If this is a simple UNION ALL query, flatten it into an appendrel. We
763: 	 * do this now because it requires applying pull_up_subqueries to the leaf
764: 	 * queries of the UNION ALL, which weren't touched above because they
765: 	 * weren't referenced by the jointree (they will be after we do this).
766: 	 */
767: 	if (parse->setOperations)
768: 		flatten_simple_union_all(root);
769: 
770: 	/*
771: 	 * Survey the rangetable to see what kinds of entries are present.  We can
772: 	 * skip some later processing if relevant SQL features are not used; for
773: 	 * example if there are no JOIN RTEs we can avoid the expense of doing
774: 	 * flatten_join_alias_vars().  This must be done after we have finished
775: 	 * adding rangetable entries, of course.  (Note: actually, processing of
776: 	 * inherited or partitioned rels can cause RTEs for their child tables to
777: 	 * get added later; but those must all be RTE_RELATION entries, so they
778: 	 * don't invalidate the conclusions drawn here.)
779: 	 */
780: 	root->hasJoinRTEs = false;
781: 	root->hasLateralRTEs = false;
782: 	root->group_rtindex = 0;
783: 	hasOuterJoins = false;
784: 	hasResultRTEs = false;
785: 	foreach(l, parse->rtable)
786: 	{
787: 		RangeTblEntry *rte = lfirst_node(RangeTblEntry, l);
788: 
789: 		switch (rte->rtekind)
790: 		{
791: 			case RTE_RELATION:
792: 				if (rte->inh)
793: 				{
794: 					/*
795: 					 * Check to see if the relation actually has any children;
796: 					 * if not, clear the inh flag so we can treat it as a
797: 					 * plain base relation.
798: 					 *
799: 					 * Note: this could give a false-positive result, if the
800: 					 * rel once had children but no longer does.  We used to
801: 					 * be able to clear rte->inh later on when we discovered
802: 					 * that, but no more; we have to handle such cases as
803: 					 * full-fledged inheritance.
804: 					 */
805: 					rte->inh = has_subclass(rte->relid);
806: 				}
807: 				break;
808: 			case RTE_JOIN:
809: 				root->hasJoinRTEs = true;
810: 				if (IS_OUTER_JOIN(rte->jointype))
811: 					hasOuterJoins = true;
812: 				break;
813: 			case RTE_RESULT:
814: 				hasResultRTEs = true;
815: 				break;
816: 			case RTE_GROUP:
817: 				Assert(parse->hasGroupRTE);
818: 				root->group_rtindex = list_cell_number(parse->rtable, l) + 1;
819: 				break;
820: 			default:
821: 				/* No work here for other RTE types */
822: 				break;
823: 		}
824: 
825: 		if (rte->lateral)
826: 			root->hasLateralRTEs = true;
827: 
828: 		/*
829: 		 * We can also determine the maximum security level required for any
830: 		 * securityQuals now.  Addition of inheritance-child RTEs won't affect
831: 		 * this, because child tables don't have their own securityQuals; see
832: 		 * expand_single_inheritance_child().
833: 		 */
834: 		if (rte->securityQuals)
835: 			root->qual_security_level = Max(root->qual_security_level,
836: 											list_length(rte->securityQuals));
837: 	}
